  assign _18_ = { _26_[10], _24_[10], _22_[10], _20_[10] } != { _20_[10], _20_[10], _20_[10], _20_[10] };
  assign _19_ = { _26_[11], _24_[11], _22_[11], _20_[11] } != { _20_[11], _20_[11], _20_[11], _20_[11] };
  assign y_o_t0 = { _19_, _18_, _17_, _16_, _15_, _14_, _13_, _12_, _11_, _10_, _09_, _08_ } | _21_;
