  assign _07_ = _00_ | s_i_t0;
  assign _03_ = _02_ & _07_[3];
  assign _05_ = 1'h1 & _07_[1];
  assign _02_ = _05_ & _07_[2];
  assign _04_ = s_i_t0 & { _03_, _02_, _05_, 1'h1 };
